-- ═════════════════════════════════════════════════════════════════════════════
-- 007_coefficient_system.sql
--
-- Система коэффициентов оценки образовательных организаций.
-- Аналог пруденциальных нормативов банков второго уровня.
--
-- Таблицы:
--   coefficient_definitions  — справочник ~170 коэффициентов
--   coefficient_records      — фактические данные (числитель/знаменатель)
--   coefficient_scores       — агрегированные баллы по принципам
--
-- Скрипт идемпотентен (IF NOT EXISTS / ON CONFLICT DO NOTHING).
-- ═════════════════════════════════════════════════════════════════════════════

BEGIN;

-- ─────────────────────────────────────────────────────────────────────────────
-- 1. coefficient_definitions
-- ─────────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS coefficient_definitions (
    id               SERIAL PRIMARY KEY,
    code             VARCHAR(20) UNIQUE NOT NULL,
    education_level  VARCHAR(10) NOT NULL,
    principle        VARCHAR(30) NOT NULL,
    number           INTEGER NOT NULL,
    name_ru          TEXT NOT NULL,
    formula_text     TEXT NOT NULL,
    formula_type     VARCHAR(20) NOT NULL,
    numerator_desc   TEXT,
    denominator_desc TEXT,
    norm_min         NUMERIC(10,4),
    norm_max         NUMERIC(10,4),
    norm_target      NUMERIC(10,4),
    is_active        BOOLEAN DEFAULT TRUE,
    created_at       TIMESTAMPTZ DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────────
-- 2. coefficient_records
-- ─────────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS coefficient_records (
    id                BIGSERIAL PRIMARY KEY,
    org_id            UUID NOT NULL REFERENCES organizations(id),
    coeff_def_id      INTEGER NOT NULL REFERENCES coefficient_definitions(id),
    period_year       INTEGER NOT NULL,
    period_quarter    INTEGER CHECK (period_quarter BETWEEN 1 AND 4),
    numerator_value   NUMERIC(18,4),
    denominator_value NUMERIC(18,4),
    coefficient_value NUMERIC(10,6),
    status            VARCHAR(20) DEFAULT 'normal',
    comment           TEXT,
    submission_status VARCHAR(20) DEFAULT 'draft',
    created_at        TIMESTAMPTZ DEFAULT NOW(),
    updated_at        TIMESTAMPTZ DEFAULT NOW(),
    created_by        UUID,
    updated_by        UUID,
    version           INTEGER DEFAULT 1,
    UNIQUE (org_id, coeff_def_id, period_year, period_quarter)
);

CREATE INDEX IF NOT EXISTS idx_coeff_records_org_year ON coefficient_records (org_id, period_year);
CREATE INDEX IF NOT EXISTS idx_coeff_records_def      ON coefficient_records (coeff_def_id);

-- ─────────────────────────────────────────────────────────────────────────────
-- 3. coefficient_scores
-- ─────────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS coefficient_scores (
    id                        BIGSERIAL PRIMARY KEY,
    org_id                    UUID NOT NULL REFERENCES organizations(id),
    education_level           VARCHAR(10) NOT NULL,
    period_year               INTEGER NOT NULL,
    score_transparency        NUMERIC(5,2),
    score_self_development    NUMERIC(5,2),
    score_financial_stability NUMERIC(5,2),
    score_safety              NUMERIC(5,2),
    score_investment_appeal   NUMERIC(5,2),
    total_score               NUMERIC(5,2),
    rating_category           VARCHAR(10),
    calculated_at             TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE (org_id, education_level, period_year)
);

CREATE INDEX IF NOT EXISTS idx_coeff_scores_org_year ON coefficient_scores (org_id, period_year);

-- ─────────────────────────────────────────────────────────────────────────────
-- 4. Seed coefficient_definitions
-- ─────────────────────────────────────────────────────────────────────────────

